//#############################################################################//

const {
    numeric,
	binary,
	enumLookup,
	temperature,
	reporting,
	humidity,
	battery,
	deviceEndpoints,
} = require('zigbee-herdsman-converters/lib/modernExtend');

const fourReporting = {min: 10, max: 1800, change: 5};
const sixReporting = {min: 3600, max: 21600, change: 1};


const definition = {
        zigbeeModel: ["EFEKTA_TH_DUO_V2_LR"],
        model: "EFEKTA_TH_DUO_V2_LR",
        vendor: "EFEKTA",
        description: "Smart device with internal and external temperature and humidity sensor.",
		icon: 'data:image/png;base64,',
        extend: [
        deviceEndpoints({endpoints: {"1": 1, "2": 2}}),

        // ---- Built-in sensor (endpoint 1) ----
        temperature({
            endpointNames: ["1"],
            description: "Temperature measured by the built-in sensor",
            reporting: fourReporting,
            access: "STATE",
        }),
        humidity({
            endpointNames: ["1"],
            description: "Humidity measured by the built-in sensor",
            reporting: fourReporting,
            access: "STATE",
        }),
        numeric({
            endpointNames: ["1"],
            name: "dew_point",
            unit: "°C",
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0341, type: 0x29},
            description: "Dew point calculated from built-in sensor data",
            scale: 100,
            access: "STATE",
        }),
        numeric({
            endpointNames: ["1"],
            name: "air_enthalpy",
            unit: "kJ/kg",
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0343, type: 0x29},
            description: "Air enthalpy derived from built-in sensor",
            scale: 100,
            access: "STATE",
        }),
        numeric({
            endpointNames: ["1"],
            name: "VPD",
            unit: "kPa",
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0340, type: 0x29},
            description: "Vapor Pressure Deficit (VPD) from built-in sensor",
            scale: 100,
            access: "STATE",
        }),
        numeric({
            endpointNames: ["1"],
            name: "temperature_offset",
            unit: "°C",
            valueMin: -50,
            valueMax: 50,
            valueStep: 0.1,
            scale: 10,
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0210, type: 0x29},
            description: "Offset calibration for the built-in temperature sensor",
            access: "STATE_SET",
        }),
        numeric({
            endpointNames: ["1"],
            name: "humidity_offset",
            unit: "%",
            valueMin: -50,
            valueMax: 50,
            valueStep: 1,
            cluster: "msRelativeHumidity",
            attribute: {ID: 0x0210, type: 0x29},
            description: "Offset calibration for the built-in humidity sensor",
            access: "STATE_SET",
        }),

        // ---- External sensor (endpoint 2) ----
        temperature({
            endpointNames: ["2"],
            description: "Temperature measured by the external sensor",
            reporting: fourReporting,
            access: "STATE",
        }),
        humidity({
            endpointNames: ["2"],
            description: "Humidity measured by the external sensor",
            reporting: fourReporting,
            access: "STATE",
        }),
        numeric({
            endpointNames: ["2"],
            name: "dew_point",
            unit: "°C",
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0341, type: 0x29},
            description: "Dew point calculated from external sensor data",
            scale: 100,
            access: "STATE",
        }),
        numeric({
            endpointNames: ["2"],
            name: "air_enthalpy",
            unit: "kJ/kg",
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0343, type: 0x29},
            description: "Air enthalpy derived from external sensor",
            scale: 100,
            access: "STATE",
        }),
        numeric({
            endpointNames: ["2"],
            name: "VPD",
            unit: "kPa",
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0340, type: 0x29},
            description: "Vapor Pressure Deficit (VPD) from external sensor",
            scale: 100,
            access: "STATE",
        }),
        numeric({
            endpointNames: ["2"],
            name: "temperature_offset",
            unit: "°C",
            valueMin: -50,
            valueMax: 50,
            valueStep: 0.1,
            scale: 10,
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0210, type: 0x29},
            description: "Offset calibration for the external temperature sensor",
            access: "STATE_SET",
        }),
        numeric({
            endpointNames: ["2"],
            name: "humidity_offset",
            unit: "%",
            valueMin: -50,
            valueMax: 50,
            valueStep: 1,
            cluster: "msRelativeHumidity",
            attribute: {ID: 0x0210, type: 0x29},
            description: "Offset calibration for the external humidity sensor",
            access: "STATE_SET",
        }),

        // ---- Battery ----
        battery({
            percentage: true,
            lowStatus: true,
            voltage: true,
            percentageReporting: true,
            voltageReporting: true,
            percentageReportingConfig: sixReporting,
            voltageReportingConfig: sixReporting,
        }),

        // ---- General settings and statuses ----
        numeric({
            name: "reading_interval",
            unit: "sec",
            valueMin: 10,
            valueMax: 360,
            cluster: "genPowerCfg",
            attribute: {ID: 0x0201, type: 0x21},
            description: "Sensor reading interval in seconds (default: 30s)",
            access: "STATE_SET",
        }),
        enumLookup({
            name: "tx_radio_power",
            lookup: {"4dbm": 4, "19dbm": 19},
            cluster: "genPowerCfg",
            attribute: {ID: 0x0236, type: 0x28},
            description: "Transmit radio power level (4 dBm or 19 dBm)",
            access: "STATE_SET",
        }),
        binary({
            name: "smart_sleep",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "genPowerCfg",
            attribute: {ID: 0x0216, type: 0x10},
            description: "Enable Smart Sleep mode (wake up every 7 seconds)",
            access: "STATE_SET",
        }),
        numeric({
            name: "uptime",
            unit: "Hours",
            cluster: "genTime",
            attribute: "standardTime",
            description: "Device uptime in hours",
            scale: 3600,
            precision: 1,
            access: "STATE",
        }),
        binary({
            name: "config_report_enable",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "genPowerCfg",
            attribute: {ID: 0x0275, type: 0x10},
            description: "Enable/disable reporting according to the configured intervals",
            access: "STATE_SET",
        }),
        binary({
            name: "comparison_previous_data",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "genPowerCfg",
            attribute: {ID: 0x0205, type: 0x10},
            description: "Enable comparison with previous sensor readings before reporting",
            access: "STATE_SET",
        }),

        // ---- Temperature control settings ----
        binary({
            name: "enable_temperature",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0220, type: 0x10},
            description: "Enable temperature monitoring and control logic",
            access: "STATE_SET",
        }),
        binary({
            name: "switching_temperature_sensor",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0229, type: 0x10},
            description: "Switch between internal and external temperature sensor for control",
            access: "STATE_SET",
        }),
        binary({
            name: "invert_logic_temperature",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0225, type: 0x10},
            description: "Invert the logic for temperature control (e.g., for heating/cooling modes)",
            access: "STATE_SET",
        }),
        numeric({
            name: "high_temperature",
            unit: "°C",
            valueMin: -40,
            valueMax: 90,
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0221, type: 0x29},
            description: "High temperature threshold for control actions",
            access: "STATE_SET",
        }),
        numeric({
            name: "low_temperature",
            unit: "°C",
            valueMin: -40,
            valueMax: 90,
            cluster: "msTemperatureMeasurement",
            attribute: {ID: 0x0222, type: 0x29},
            description: "Low temperature threshold for control actions",
            access: "STATE_SET",
        }),

        // ---- Humidity control settings ----
        binary({
            name: "enable_humidity",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "msRelativeHumidity",
            attribute: {ID: 0x0220, type: 0x10},
            description: "Enable humidity monitoring and control logic",
            access: "STATE_SET",
        }),
        binary({
            name: "switching_humidity_sensor",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "msRelativeHumidity",
            attribute: {ID: 0x0229, type: 0x10},
            description: "Switch between internal and external humidity sensor for control",
            access: "STATE_SET",
        }),
        binary({
            name: "invert_logic_humidity",
            valueOn: ["ON", 1],
            valueOff: ["OFF", 0],
            cluster: "msRelativeHumidity",
            attribute: {ID: 0x0225, type: 0x10},
            description: "Invert the logic for humidity control (e.g., for humidifier/dehumidifier modes)",
            access: "STATE_SET",
        }),
        numeric({
            name: "high_humidity",
            unit: "%",
            valueMin: 0,
            valueMax: 99,
            cluster: "msRelativeHumidity",
            attribute: {ID: 0x0221, type: 0x29},
            description: "High humidity threshold for control actions",
            access: "STATE_SET",
        }),
        numeric({
            name: "low_humidity",
            unit: "%",
            valueMin: 0,
            valueMax: 99,
            cluster: "msRelativeHumidity",
            attribute: {ID: 0x0222, type: 0x29},
            description: "Low humidity threshold for control actions",
            access: "STATE_SET",
        }),
    ],
};

module.exports = definition;